// Orchestration-based saga step definition
interface SagaStep<C> {
  name: string;
  invoke: (ctx: C) => Promise<void>;     // forward action (local txn)
  compensate: (ctx: C) => Promise<void>; // semantic undo, idempotent
}

const orderSaga: SagaStep<OrderContext>[] = [
  { name: 'createOrder',
    invoke: ctx => orders.create(ctx.orderId, 'PENDING'),
    compensate: ctx => orders.cancel(ctx.orderId) },
  { name: 'reserveStock',
    invoke: ctx => inventory.reserve(ctx.orderId, ctx.items),
    compensate: ctx => inventory.release(ctx.orderId) },
  { name: 'capturePayment',
    invoke: ctx => payments.capture(ctx.orderId, ctx.amount),
    compensate: ctx => payments.refund(ctx.orderId) },
];

// Propagate W3C trace context across a service hop (OpenTelemetry)
import { context, propagation, trace } from '@opentelemetry/api';

async function callInventory(items: Item[]) {
  const headers: Record<string, string> = {};
  // Inject current trace context into outbound headers
  propagation.inject(context.active(), headers);
  return fetch('http://inventory.shop.svc:8080/reserve', {
    method: 'POST',
    headers: { 'content-type': 'application/json', ...headers },
    body: JSON.stringify({ items }),
  });
  // Inventory extracts traceparent and continues the same trace,
  // so the whole request shows up as one waterfall in Jaeger.
}

// The fix: idempotency key + treat timeout as UNKNOWN, then reconcile.
async function capturePayment(ctx: OrderContext): Promise<CaptureResult> {
  const key = `capture:${ctx.orderId}`; // stable per logical operation
  try {
    return await psp.capture({ idempotencyKey: key, amount: ctx.amount });
  } catch (e) {
    if (isTimeout(e)) {
      // DO NOT compensate blindly. Outcome is UNKNOWN.
      // Enqueue a reconciliation job that polls the PSP by idempotencyKey.
      await reconciliationQueue.enqueue({ orderId: ctx.orderId, key });
      throw new SagaPendingError('payment outcome unknown, reconciling');
    }
    throw e; // a definite decline -> safe to compensate
  }
}

