type Ctx = { orderId: string; items: { sku: string; qty: number }[]; amount: number };

interface Step {
  name: string;
  invoke: (c: Ctx) => Promise<void>;
  compensate: (c: Ctx) => Promise<void>; // MUST be idempotent
}

async function withRetry(fn: () => Promise<void>, tries = 5): Promise<void> {
  let lastErr: unknown;
  for (let i = 0; i < tries; i++) {
    try { return await fn(); }
    catch (e) { lastErr = e; await sleep(2 ** i * 50 + Math.random() * 50); }
  }
  throw lastErr; // exhausted retries -> escalate to dead-letter / on-call
}

async function runSaga(steps: Step[], ctx: Ctx): Promise<'COMPLETED' | 'COMPENSATED'> {
  const done: Step[] = [];
  try {
    for (const step of steps) {
      await step.invoke(ctx); // each is a local txn in its own service
      done.push(step);
    }
    return 'COMPLETED';
  } catch (err) {
    // Forward step failed -> compensate completed steps in REVERSE order.
    for (const step of done.reverse()) {
      // Compensations are idempotent + retried; never throw out of the loop.
      await withRetry(() => step.compensate(ctx)).catch(e =>
        escalate(`compensation failed: ${step.name}`, e));
    }
    return 'COMPENSATED';
  }
}

const checkoutSteps: Step[] = [
