import { Pool } from 'pg';
const pool = new Pool();

interface OrderPaid { eventId: string; orderId: string; amount: number; }

async function handleOrderPaid(evt: OrderPaid): Promise<void> {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    // 1) Dedup guard: insert the event id; conflict => already processed.
    const dedup = await client.query(
      `INSERT INTO processed_events (event_id, processed_at)
       VALUES ($1, now())
       ON CONFLICT (event_id) DO NOTHING
       RETURNING event_id`,
      [evt.eventId],
    );

    if (dedup.rowCount === 0) {
      // Duplicate delivery: side effect already applied. Ack and return.
      await client.query('ROLLBACK');
      return;
    }

    // 2) Side effect, in the SAME transaction as the dedup insert.
    await client.query(
      `UPDATE orders SET status = 'PAID' WHERE id = $1 AND status <> 'PAID'`,
      [evt.orderId],
    );
    await client.query(
      `INSERT INTO ledger (order_id, delta) VALUES ($1, $2)`,
      [evt.orderId, evt.amount],
    );

    // 3) Commit dedup + side effect atomically.
    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK'); // not acked -> broker redelivers, safe
    throw e;
  } finally {
    client.release();
  }
}
